class Pythontools:
    def __init__(self,blingbling, *args, **kwargs):
        self.listed_dict = lambda blingbling: [f"{k}" for k in blingbling.items()]
        self.blingbling = blingbling

    def dataset(self):
        completed_list = ""
        for iter, dictionary in enumerate(self.blingbling):
            if iter == 0:
                completed_list += f"[{dictionary}"
                continue
            elif iter == len(self.blingbling)-1:
                completed_list += f",\n {dictionary}]"
                return completed_list
            if not "id" in dictionary:
                continue
            
            completed_list += f",\n {dictionary}"
